html:
{% set emp = frappe.db.get_value(
    "UOT Employees",
    doc.employee,
    ["employee_full_name", "employee_department_or_division"],
    as_dict=True
) %}

{% set dept_name = frappe.db.get_value(
    "UOT Departments",
    emp.employee_department_or_division,
    "department_name"
) %}

{% set leave_type_arabic = frappe.db.get_value(
    "UOT Leave Type",
    doc.leave_type,
    "leave_type"
) %}

<!DOCTYPE html>
<html>
<head>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Cairo:wght@200..1000&display=swap" rel="stylesheet">
    <meta http-equiv="Content-Type" content="text/html; charset=utf-8"/>
    <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
    <meta charset="UTF-8">
    <style>
        @page {
            size: A4;
            margin: 1.5cm 2cm;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            font-family: "Cairo";
            font-size: 13pt;
            color: #1a1a1a;
            background: white;
            direction: rtl;
            border:2px;
        }

        .page {
            width: 100%;
            height: 100%;
            direction: rtl;
            text-align: right;

        }

        /* Header */
        .header {
            text-align: center;
            border-bottom: 2px solid #1a3a6b;
            padding-bottom: 10px;
            margin-bottom: 15px;
        }

        .header .university {
            font-size: 17pt;
            font-weight: bold;
            color: #1a3a6b;
        }

        .header .sub {
            font-size: 16pt;
            color: #555;
            margin-top: 3px;
        }

        /* Recipients */
        .recipients {
            margin-bottom: 12px;
            padding: 8px 12px;
            border-right: 3px solid #1a3a6b;
           /* background: #f7f9ff; */
        }

        .recipients p {
            font-size: 14pt;
            font-weight: bold;
            color: #1a3a6b;
            line-height: 1.8;
            direction: rtl;
            text-align: right;
        }

        /* Subject */
        .subject {
            text-align: center;
            margin: 12px 0;
        }

        .subject-inner {
            display: inline-block;
            font-size: 14pt;
            font-weight: bold;
            color: #1a3a6b;
            padding: 5px 30px;
        }

        /* Body text */
        .greeting {
            font-size: 12pt;
            margin-bottom: 8px;
            direction: rtl;
            text-align: right;
        }

        .body-text {
            font-size: 12pt;
            line-height: 2;
            direction: rtl;
            text-align: justify;
            margin-bottom: 10px;
            padding: 10px;
            border: 1px solid #d0d8f0;
            border-radius: 4px;
        }

        .value {
            padding: 0 6px;
            color: #1a3a6b;
            font-weight: bold;
        }

        .appreciation {
            font-size: 12pt;
            margin: 8px 0 20px 0;
            direction: rtl;
            text-align: center;
        }

        /* Employee info table */
        .info-table td {
            padding: 8px 15px;
            font-size: 12pt;
            direction: rtl;
            text-align: right;
            vertical-align: middle;
        }

        .info-table .table-header {
            background: #1a3a6b;
            color: white;
            padding: 6px 12px;
            font-size: 11pt;
            font-weight: bold;
            direction: rtl;
            text-align: right;
        }

        .info-table tr {
            border-bottom: 1px solid #e8edf8;
        }

        .info-table tr:last-child {
            border-bottom: none;
        }

        .info-table td {
            padding: 6px 12px;
            font-size: 12pt;
            direction: rtl;
            text-align: right;
        }

        .info-table .label {
            font-weight: bold;
            color: #444;
            width: 35%;
            border-left: none;
            border-right: none;
            padding-top: 10px;
        }

        .info-table .val {
            color: #1a1a1a;
        }

        /* Approvals */
        .approvals {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 12px;
            border: 1px solid #d0d8f0;
        }

        .approvals .table-header {
            background: #1a3a6b;
            color: white;
            padding: 6px 12px;
            font-size: 11pt;
            font-weight: bold;
            direction: rtl;
            text-align: right;
        }

        .approvals tr {
            border-bottom: 1px solid #e8edf8;
        }

        .approvals tr:last-child {
            border-bottom: none;
        }

        .approvals td {
            padding: 8px 15px;
            font-size: 12pt;
            direction: rtl;
            text-align: right;
            vertical-align: middle;
        }     

        .approvals .num {
            color: #1a3a6b;
            font-weight: bold;
            width: 30px;
        }

        .approvals .approval-label {
            width: 55%;
        }

        .approvals .sig-line {
            border-bottom: 1px dotted #999;
            width: 100%;
            display: inline-block;
            height: 18px;
            vertical-align: middle;
            text-align: center;
        }

        /* Notes */
        .notes {
            border: 1px solid #e8d080;
            border-radius: 4px;
            padding: 8px 12px;
            background: #fffdf0;
            margin-bottom: 12px;
        }

        .notes .notes-title {
            font-size: 12pt;
            font-weight: bold;
            color: #7a6000;
            margin-bottom: 5px;
            direction: rtl;
            text-align: right;
        }

        .notes p {
            font-size: 11pt;
            color: #555;
            line-height: 1.8;
            direction: rtl;
            text-align: right;
        }

        /* Footer */
        .footer {
            text-align: center;
            font-size: 9pt;
            color: #aaa;
            border-top: 1px solid #ddd;
            padding-top: 6px;
        }
    </style>
</head>
<body>
<div class="page">

    <!-- Header -->
    <div class="header">
        <div class="university">الجامعة التكنولوجية - كلية الهندسة الميكانيكية</div>
        <div class="sub">استمارة التقديم على اجازة الامومة</div>
    </div>

    <!-- Recipients -->
    <div class="recipients">
        <p>السيد عميد الكلية المحترم ....</p>
        <p>السيد المعاون الإداري المحترم ....</p>
    </div>

    <!-- Subject -->
    <div class="subject">
        <span class="subject-inner">م / {{ leave_type_arabic or doc.leave_type }}</span>
    </div>

    <!-- Greeting -->
    <div class="greeting">تحية طيبة ....</div>

    <!-- Body -->
    <div class="body-text">
        أرجو التفضل بالموافقة على تمتعي بـ
        <span class="value">{{ leave_type_arabic or doc.leave_type }}</span>
        والبالغة مدتها
        <span class="value">{{ doc.days_count_of_leave }} يوم</span>
        إعتباراً من
        <span class="value">{{ doc.from_day }}</span>
        ولغاية
        <span class="value">{{ doc.to_day }}</span>
        {% if doc.reason_for_leave %} ، {{ doc.reason_for_leave }} {% endif %}
    </div>

    <!-- Appreciation -->
    <div class="appreciation">مـــــع التقدير ......</div>

    <!-- Employee Info -->
    <table class="approvals">
        <tr>
            <td colspan="2" class="table-header" style="text-align:center;">معلومات مقدم الطلب</td>
        </tr>
        <tr>
            <td class="val">الاسم الكامل واللقب :-</td>
            <td class="val" style="text-align:center;">{{ doc.data_lprk }}</td>
        </tr>
        <tr>
            <td class="val">الرقم الوظيفي :-</td>
            <td class="val" style="text-align:center;">{{ doc.employee }}</td>
        </tr>
        <tr>
            <td class="val">رقم الطلب :-</td>
            <td class="val" style="text-align:center;">{{ doc.name }}</td>
        </tr>        
        <!--
        <tr>
            <td class="val">التاريخ :-</td>
            <td class="val">
                {% if doc.creation %}
                    {% if doc.creation is string %}
                        {{ doc.creation.split(' ')[0].replace('-', '/') }}
                    {% else %}
                        {{ doc.creation.strftime('%Y/%m/%d') }}
                    {% endif %}
                {% endif %}
            </td>
        </tr>
        -->

    </table>

    <!-- Approvals -->
    <table class="approvals">
        <tr>
            <td colspan="3" class="table-header" style="text-align:center;">الموافقات</td>
        </tr>
        <tr>
            <td class="num">-</td>
            <td class="approval-label">تاريخ أول تعيين :-</td>
            {% set date_of_appointment = frappe.db.get_value("UOT Employees", doc.employee, "date_of_appointment") %}
            <td><span class="sig-line">{{date_of_appointment}}</span></td>
        </tr>
        <tr>
            <td class="num">-</td>
            <td class="approval-label">هل سبق ومنحت {{ leave_type_arabic or doc.leave_type }} :-</td>
            <td><span class="sig-line"></span></td>
        </tr>
        <tr>
            <td class="num">-</td>
            <td class="approval-label">موافقة مساعد رئيس الجامعة أو من يخول عنه :-</td>
            <td><span class="sig-line"></span></td>
        </tr>
    </table>

    <!-- Notes -->
    <div class="notes">
        <div class="notes-title">ملاحظة :-</div>
        <p>ـ يورد الطلب بتاريخ التقديم من وارد الجامعة .</p>
        <p>ـ يرفق بالطلب بيان الولادة .</p> 
    </div>

    <!-- Footer -->
    <div class="footer">
       نظام الاجازات - كلية الهندسة الميكانيكية - شعبة الموارد البشرية
    </div>

</div>
</body>
</html>
